use bids_rust::{BidsProject, BidsError};
use std::path::Path;
use tempfile::TempDir;
use std::fs;

#[test]
fn test_create_bids_project_valid_directory() {
    // Create a temporary BIDS-like directory structure
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create basic BIDS structure
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/anat")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/func")).unwrap();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Test Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create some BIDS files
    fs::write(
        root_path.join("sub-01/func/sub-01_task-rest_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-01/anat/sub-01_T1w.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create project
    let project = BidsProject::new(root_path).unwrap();

    assert_eq!(project.name, "Test Dataset");
    assert_eq!(project.path, root_path);
    assert!(!project.has_sessions);
}

#[test]
fn test_create_bids_project_with_sessions() {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create BIDS structure with sessions
    fs::create_dir_all(root_path.join("sub-01/ses-01/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-01/ses-02/func")).unwrap();
    fs::create_dir_all(root_path.join("sub-02/ses-01/func")).unwrap();

