use bids_rust::{BidsProject, BidsFile, BidsParser, SearchBuilder};
use std::path::Path;
use tempfile::TempDir;
use std::fs;

/// This test module ensures feature parity with the R bidser package
/// by replicating all critical test cases from the R implementation

// ============================================================================
// BIDS Project Tests (equivalent to R test-bids_project.R)
// ============================================================================

#[test]
fn test_bids_project_initialization() {
    // Test basic project initialization - R equivalent: test_that("bids_project initializes correctly")
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    // Create minimal BIDS structure
    fs::create_dir_all(root.join("sub-01/func")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    let project = BidsProject::new(root).unwrap();
    assert_eq!(project.name, "Test");
}

#[test]
fn test_bids_project_with_participants_tsv() {
    // R equivalent: test_that("participants.tsv is parsed correctly")
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    fs::create_dir(root.join("sub-01")).unwrap();
    fs::create_dir(root.join("sub-02")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();
    fs::write(root.join("participants.tsv"), "participant_id\tage\tsex\nsub-01\t25\tM\nsub-02\t30\tF\n").unwrap();

    let project = BidsProject::new(root).unwrap();
    let participants = project.get_participants();
    assert_eq!(participants.len(), 2);
}

#[test]
fn test_bids_project_detect_sessions() {
    // R equivalent: test_that("sessions are detected correctly")
    let temp_dir = TempDir::new().unwrap();
    let root = temp_dir.path();

    fs::create_dir_all(root.join("sub-01/ses-01/func")).unwrap();
    fs::create_dir_all(root.join("sub-01/ses-02/func")).unwrap();
    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    let project = BidsProject::new(root).unwrap();
    assert!(project.has_sessions);

    let sessions = project.get_sessions("sub-01");
    assert_eq!(sessions.len(), 2);
}

// ============================================================================
// BIDS Filename Parsing Tests (equivalent to R test-parse_bids.R)
// ============================================================================

#[test]
fn test_parse_bids_filename_basic() {
    // R equivalent: test_that("basic BIDS filenames parse correctly")
    let parser = BidsParser::new();

    // Test cases from R implementation
    let test_cases = vec![
        ("sub-01_task-rest_bold.nii.gz", "sub-01", None, Some("rest"), "bold"),
        ("sub-02_ses-01_T1w.nii.gz", "sub-02", Some("ses-01"), None, "T1w"),
        ("sub-03_task-nback_run-1_bold.json", "sub-03", None, Some("nback"), "bold"),
    ];

    for (filename, expected_sub, expected_ses, expected_task, expected_suffix) in test_cases {
        let result = parser.parse(filename).unwrap();
        assert_eq!(result.get_entity("sub"), Some(expected_sub));
        assert_eq!(result.get_entity("ses"), expected_ses);
        assert_eq!(result.get_entity("task"), expected_task);
        assert_eq!(result.suffix.as_deref(), Some(expected_suffix));
    }
}

#[test]
fn test_parse_bids_filename_with_all_entities() {
    // R equivalent: test_that("filenames with multiple entities parse correctly")
    let parser = BidsParser::new();
    let filename = "sub-01_ses-02_task-rest_acq-mb3_run-1_bold.nii.gz";

    let result = parser.parse(filename).unwrap();
    assert_eq!(result.get_entity("sub"), Some("01"));
    assert_eq!(result.get_entity("ses"), Some("02"));
    assert_eq!(result.get_entity("task"), Some("rest"));
    assert_eq!(result.get_entity("acq"), Some("mb3"));
    assert_eq!(result.get_entity("run"), Some("1"));
}

#[test]
fn test_parse_invalid_bids_filename() {
