    let modalities = vec!["anat", "func", "dwi", "fmap", "perf"];
    for modality in &modalities {
        fs::create_dir_all(root.join(format!("sub-01/{}", modality))).unwrap();
    }

    fs::write(root.join("dataset_description.json"), r#"{"Name": "Test", "BIDSVersion": "1.6.0"}"#).unwrap();

    // Create files for each modality
